const body = $input.first().json.body ?? $input.first().json;
const { vacancy_url, vacancy_text, company_site, company_text } = body;

const url = vacancy_url || 'https://test.local/vacancy/0';

const source = url.includes('hh.ru') ? 'hh'
  : url.includes('linkedin.com') ? 'linkedin'
  : url.includes('superjob.ru') ? 'superjob'
  : url.includes('t.me') ? 'telegram'
  : url.includes('zarplata.ru') ? 'zarplata'
  : url.includes('habr.com') ? 'habr'
  : 'other';

return [{ json: {
  vacancyText: [vacancy_text, company_text]
    .filter(Boolean)
    .join('\n\n--- Компания ---\n'),
  link: url.split('?')[0],
  site: company_site || null,
  source,
}}];

const raw = $input.first().json.text;

// Чистим think-блоки Llama и markdown
const cleaned = raw
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  throw new Error(`Parser LLM returned invalid JSON: ${error.message}\n\n${cleaned.slice(0, 1000)}`);
}

parsed.vacancy = parsed.vacancy || {};
parsed.company = parsed.company || {};

const codeNode = $('Parse Input').first().json;

// ── Vacancy ──────────────────────────────────────────
// link и source всегда из Parse Input — они точнее чем от LLM
parsed.vacancy.link = codeNode.link || null;
parsed.vacancy.source = codeNode.source || 'telegram';
parsed.vacancy.status = 'new';

// Чистим поля которые LLM иногда пишет текстом вместо null
const nullIfEmpty = (val) =>
  (!val || ['не указано', 'не указана', 'не определено', 'null'].includes(String(val).toLowerCase().trim()))
    ? null
    : val;

parsed.vacancy.salary        = nullIfEmpty(parsed.vacancy.salary);
parsed.vacancy.salary_raw    = nullIfEmpty(parsed.vacancy.salary_raw);
parsed.vacancy.salary_comment = nullIfEmpty(parsed.vacancy.salary_comment);
parsed.vacancy.format        = nullIfEmpty(parsed.vacancy.format);
parsed.vacancy.city          = nullIfEmpty(parsed.vacancy.city);
parsed.vacancy.experience    = nullIfEmpty(parsed.vacancy.experience);
parsed.vacancy.employment    = nullIfEmpty(parsed.vacancy.employment);
parsed.vacancy.relocation    = nullIfEmpty(parsed.vacancy.relocation);
parsed.vacancy.visa_support  = nullIfEmpty(parsed.vacancy.visa_support);
parsed.vacancy.reason        = nullIfEmpty(parsed.vacancy.reason);

// Массивы — гарантируем что это всегда массив
parsed.vacancy.hard_skills = Array.isArray(parsed.vacancy.hard_skills) ? parsed.vacancy.hard_skills : [];
parsed.vacancy.soft_skills = Array.isArray(parsed.vacancy.soft_skills) ? parsed.vacancy.soft_skills : [];

// ── Company ──────────────────────────────────────────
// Сайт: сначала из Parse Input, потом от LLM
parsed.company.site = codeNode.site || parsed.company.site || null;

parsed.company.size         = nullIfEmpty(parsed.company.size);
parsed.company.size_comment = nullIfEmpty(parsed.company.size_comment);
parsed.company.stage        = nullIfEmpty(parsed.company.stage);
parsed.company.branch       = nullIfEmpty(parsed.company.branch);
parsed.company.name         = nullIfEmpty(parsed.company.name);

// ── Финальный объект ─────────────────────────────────
return [{ json: {
  ...parsed,
  // Шорткаты для удобства в следующих нодах
  companyName:   parsed.company.name,
  companyBranch: parsed.company.branch,
  companySite:   parsed.company.site,
  companyStage:  parsed.company.stage,
  companySize:   parsed.company.size,
  vacancyCity:   parsed.vacancy.city,
  vacancyFormat: parsed.vacancy.format,
  hardSkills:    parsed.vacancy.hard_skills,
}}];

const html = $input.first().json.data;

const text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 3000);

return [{ json: { siteContent: text }}];

const raw = $input.first().json.text ?? '';

const cleaned = raw
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');

if (start === -1 || end === -1 || end <= start) {
  throw new Error(`Score LLM returned no JSON object:\n\n${cleaned.slice(0, 1000)}`);
}

const jsonText = cleaned.slice(start, end + 1);

let parsed;
try {
  parsed = JSON.parse(jsonText);
} catch (error) {
  throw new Error(`Score LLM returned invalid JSON: ${error.message}\n\n${jsonText.slice(0, 1000)}`);
}

return [{ json: parsed }];

