let siteContent = null;

try {
  siteContent = $('Clean HTML').first().json.siteContent;
} catch (e) {
  siteContent = null;
}

try {
  siteContent = siteContent ?? $('Empty site content').first().json.siteContent;
} catch (e) {}

let tavilyResearch = null;
let tavilySources = [];

try {
  const tavily = $('Search').first().json;

  const answer = tavily.answer ? `Краткий ответ поиска:\n${tavily.answer}` : '';

  const results = (tavily.results ?? [])
    .map((result, index) => {
      const title = result.title ?? 'Без заголовка';
      const url = result.url ?? '';
      const content = result.content ?? '';
      return `${index + 1}. ${title}\nURL: ${url}\n${content}`;
    })
    .join('\n\n');

  tavilyResearch = [answer, results].filter(Boolean).join('\n\n---\n\n');

  tavilySources = (tavily.results ?? []).map(result => ({
    title: result.title,
    url: result.url,
    score: result.score,
  }));
} catch (e) {
  tavilyResearch = null;
  tavilySources = [];
}

const ctx = $('Prepare vacancy context').first().json;

return [{
  json: {
    vacancyId: ctx.vacancyId,

    companyName: ctx.companyName ?? null,
    companyBranch: ctx.companyBranch ?? null,
    companySite: ctx.companySite ?? null,
    companyStage: ctx.companyStage ?? null,
    companySize: ctx.companySize ?? null,

    siteContent: siteContent || 'Сайт не предоставлен или не был обработан',
    webResearch: tavilyResearch || 'Поиск по компании не дал полезной информации',
    webSources: tavilySources,

    role: ctx.role ?? null,
    about: ctx.about ?? null,
    salary: ctx.salary ?? null,
    format: ctx.format ?? null,
    city: ctx.city ?? null,
    experience: ctx.experience ?? null,
    employment: ctx.employment ?? null,
    hardSkills: ctx.hardSkills ?? [],
    softSkills: ctx.softSkills ?? [],
  }
}];

let vacancy = null;

try {
  vacancy = $('Update vacancies').first().json;
} catch (e) {
  vacancy = null;
}

if (!vacancy?.id) {
  vacancy = $('Create vacancies').first().json;
}

if (!vacancy?.id) {
  throw new Error('No vacancy id after create/update');
}

return [{ json: vacancy }];

