const body = $input.first().json.body ?? $input.first().json;

const vacancyIds = body.vacancy_ids ?? [];
const promptVersions = body.prompt_versions ?? {};

if (!Array.isArray(vacancyIds) || vacancyIds.length === 0) {
  throw new Error('reanalyze webhook requires vacancy_ids array');
}

return vacancyIds.map(vacancyId => ({
  json: {
    vacancyId,
    promptVersions,
  },
}));

let source = 'parser';

let vacancyResult = null;
let parsed = null;
let vacancy = {};
let company = {};

try {
  vacancyResult = $('Prepare vacancy result').first().json;
  parsed = $('Parse LLM Response').first().json;
  vacancy = parsed.vacancy ?? {};
  company = parsed.company ?? {};
} catch (e) {
  source = 'reanalyze';
}

